import { Booking } from '@/models/booking.dto';
import { Agent } from '@/services/agents/type';
import { Component, Event, EventEmitter, Prop, State, Watch, h } from '@stencil/core';
import { isAgentMode } from '../ir-booking-details/functions';

export type BillingPanels = 'agent' | 'guest';
@Component({
  tag: 'ir-billing',
  styleUrl: 'ir-billing.css',
  scoped: true,
})
export class IrBilling {
  @Prop() booking: Booking;
  @Prop() isAllServicesAgentOwned: boolean;
  @Prop() agent: Agent;
  @Watch('agent')
  async handleBookingChange() {
    this.isAgentMode = isAgentMode(this.agent);
  }

  @State() isAgentMode: boolean = false;
  @State() currentTab: BillingPanels = 'agent';

  @Event() billingClose: EventEmitter<void>;

  componentWillLoad() {
    this.isAgentMode = isAgentMode(this.agent);
  }

  render() {
    if (this.isAgentMode) {
      return (
        <wa-tab-group
          activation="manual"
          onwa-tab-show={e => {
            e.stopImmediatePropagation();
            e.stopPropagation();
            this.currentTab = e.detail.name.toString() as BillingPanels;
          }}
          active={this.currentTab}
        >
          <wa-tab panel="guest" disabled={this.isAllServicesAgentOwned}>
            Guest
          </wa-tab>
          <wa-tab panel="agent">Agent</wa-tab>
          <wa-tab-panel name="guest" active={this.currentTab === 'guest'}>
            {this.currentTab === 'guest' && <ir-guest-billing booking={this.booking}></ir-guest-billing>}
          </wa-tab-panel>
          <wa-tab-panel name="agent" active={this.currentTab === 'agent'}>
            {this.currentTab === 'agent' && <ir-agent-billing booking={this.booking}></ir-agent-billing>}
          </wa-tab-panel>
        </wa-tab-group>
      );
    }
    return <ir-guest-billing booking={this.booking}></ir-guest-billing>;
  }
}
